  "data": {
    "questions": [
      {
        "question": "What type of dress is most suitable for ballroom dancing?",
        "options": [
          "A-line dress",
          "Mini skirt",
          "Maxi dress",
          "T-shirt dress"
        ],
        "correctAnswer": 0,
        "explanation": "An A-line dress allows for ease of movement and is flattering for ballroom dancing."
      },
      {
        "question": "Which fabric is best for a dance dress?",
        "options": [
          "Cotton",
          "Silk",
          "Denim",
          "Wool"
        ],
        "correctAnswer": 1,
        "explanation": "Silk provides a smooth flow and is often used for dance dresses."
      },
      {
        "question": "What length is recommended for a dance dress?",
        "options": [
          "Above the knee",
          "Knee-length",
          "Ankle-length",
          "Floor-length"
        ],
        "correctAnswer": 3,
        "explanation": "Floor-length dresses are often preferred for their elegance in dance."
      },
      {
        "question": "Which accessory is important to consider with a dance dress?",
        "options": [
          "Sunglasses",
          "Jewelry",
          "Belt",
          "Hat"
        ],
        "correctAnswer": 1,
        "explanation": "Jewelry can enhance the overall look of a dance dress."
      }
    ]
  }
